        let privateKey = P256.Signing.PrivateKey()
        let publicKey = privateKey.publicKey
        return (privateKey.rawRepresentation, publicKey.rawRepresentation)
    }
    
    func signTransaction(transactionData: Data, privateKey: Data) -> Data? {
        guard let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateKey) else {
            return nil
        }
        
        return try? privateKey.signature(for: transactionData)
    }
    
    func storePrivateKey(_ privateKey: Data, for identifier: String) -> Bool {
        guard let keychainData = try? KeychainManager.store(key: identifier, data: privateKey) else {
            return false
        }
        return keychainData != nil
    }
    
    func retrievePrivateKey(for identifier: String) -> Data? {
        return try? KeychainManager.retrieve(key: identifier)
    }
}

// MARK: - Keychain Manager
class KeychainManager {
    static func store(key: String, data: Data) throws -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    static func retrieve(key: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess, let data = result as? Data {
            return data
        }
        
        throw KeychainError.noData
    }
}

enum KeychainError: Error {
    case noData
}

